select count(*) from postgres.comments as c, postgres.posts as p, postgres.postlinks as pl, postgres.posthistory as ph, postgres.votes as v where p.id = pl.postid and p.id = v.postid and p.id = ph.postid and p.id = c.postid and c.creationdate<=timestamp '2014-09-10 02:42:35' and p.score>=-1 and p.viewcount<=5896 and p.answercount>=0 and p.creationdate>=timestamp '2010-07-29 15:57:21' and v.votetypeid=2;
